class LogManager:
    def __init__(self, es_manager: ElasticsearchManager, index_prefix: str = 'logs'):
        self.es_manager = es_manager
        self.index_prefix = index_prefix
        self._setup_log_index()
    
    def _setup_log_index(self):
        index_name = f"{self.index_prefix}-{datetime.now().strftime('%Y.%m')}"
        
        mappings = {
            'properties': {
                'timestamp': {'type': 'date'},
                'level': {'type': 'keyword'},
                'message': {'type': 'text'},
                'service': {'type': 'keyword'},
                'host': {'type': 'keyword'},
                'user': {'type': 'keyword'},
                'tags': {'type': 'keyword'},
                'metadata': {'type': 'object', 'enabled': True}
            }
        }
        
        settings = {
            'number_of_shards': 1,
            'number_of_replicas': 1,
            'index': {
                'refresh_interval': '5s'
            }
        }
        
        try:
            self.es_manager.create_index(index_name, mappings, settings)
        except Exception as e:
            logger.info(f"Index setup: {e}")
    
    def _get_current_index(self):
        return f"{self.index_prefix}-{datetime.now().strftime('%Y.%m')}"
    
    def log(self, level: str, message: str, service: str = None, host: str = None,
            user: str = None, tags: List[str] = None, metadata: Dict = None):
        log_entry = {
            'timestamp': datetime.utcnow().isoformat(),
            'level': level.upper(),
            'message': message
        }
        
        if service:
            log_entry['service'] = service
        if host:
            log_entry['host'] = host
        if user:
            log_entry['user'] = user
        if tags:
            log_entry['tags'] = tags
        if metadata:
            log_entry['metadata'] = metadata
        
        index_name = self._get_current_index()
        return self.es_manager.index_document(index_name, log_entry)
    
    def info(self, message: str, **kwargs):
        return self.log('INFO', message, **kwargs)
    
    def warning(self, message: str, **kwargs):
        return self.log('WARNING', message, **kwargs)
    
    def error(self, message: str, **kwargs):
        return self.log('ERROR', message, **kwargs)
    
    def debug(self, message: str, **kwargs):
        return self.log('DEBUG', message, **kwargs)
    
    def critical(self, message: str, **kwargs):
        return self.log('CRITICAL', message, **kwargs)
    
